/**
 * @shardworks/laboratory-apparatus — The Laboratory.
 *
 * Apparatus for running trial-shaped experiments on guild
 * configurations. Audiences:
 *
 *   - **Nexus dev:** cost/quality tuning (P3 work, prompt evaluation,
 *     plugin variant comparison) — automate the experimental-
 *     infrastructure spec at experiments/infrastructure/setup-and-
 *     artifacts.md.
 *   - **End users:** evaluate their own prompts/plugins/configs by
 *     authoring trial manifests against a stable apparatus surface.
 *
 * Architecture (MVP0):
 *
 *   - One writ type: `trial` — a single execution unit. Lifecycle
 *     mirrors mandate. (Higher-level `experiment` grouping is parked
 *     for v2; click c-momaacry.)
 *   - One canonical rig template: `post-and-collect-default` —
 *     composes fixture-setup, scenario, probes, teardown, and archive
 *     engines from the writ's `ext.laboratory.config`.
 *   - Engines: fixtures (setup/teardown, DAG), scenario (cross-guild
 *     commission post + wait), probes (data extraction), archive
 *     (still in design at click c-momaa5o9).
 *
 * The plugin is currently a skeleton — only the trial writ-type
 * registration is wired. Engine designs, rig templates, and CLI tools
 * are added as their respective implementation children land.
 *
 * See: experiments/infrastructure/setup-and-artifacts.md
 */

import type { Plugin } from '@shardworks/nexus-core';
import { guild } from '@shardworks/nexus-core';
import type { ClerkApi } from '@shardworks/clerk-apparatus';

// ── Public type re-exports ───────────────────────────────────────────

export {
  TRIAL_TYPE_NAME,
  TRIAL_WRIT_TYPE_CONFIG,
} from './types.ts';
export type {
  LaboratoryConfig,
  LaboratoryTrialConfig,
  TrialFixtureDecl,
  TrialScenarioDecl,
  TrialProbeDecl,
  TrialArchiveDecl,
  TrialSlug,
} from './types.ts';

// ── Apparatus ────────────────────────────────────────────────────────

import { TRIAL_WRIT_TYPE_CONFIG } from './types.ts';
import { engines } from './engines/index.ts';
import { rigTemplates, rigTemplateMappings } from './template.ts';
import { tools } from './tools/index.ts';

const laboratoryPlugin: Plugin = {
  apparatus: {
    /**
     * Hard requires — apparatuses whose APIs the Laboratory's startup
     * code calls directly (clerk for writ-type registration), plus
     * those whose presence is structurally needed for the lab's
     * contributions to be useful (spider for rig-template execution,
     * fabricator for engine-design registration). Stacks is required
     * transitively via clerk.
     */
    requires: ['stacks', 'clerk', 'spider', 'fabricator'],

    /**
     * Recommended at startup; required at engine-execution time when
     * the relevant fixture or scenario engine actually fires. Marking
     * them as recommends (not requires) lets a guild start the lab
     * without these installed — the trials that touch the missing
     * surface fail when their engine runs, not at startup.
     */
    recommends: ['codexes', 'animator'],

    /**
     * Kit contributions wired up:
     *
     *   - `engines`              — every Laboratory engine design
     *                               (5 phase orchestrators + the
     *                               work-engine stubs that get
     *                               grafted by them). Stubs land
     *                               their real behavior under their
     *                               respective implementation clicks.
     *   - `rigTemplates`         — `post-and-collect-default` —
     *                               enumerates the five phase
     *                               orchestrators in sequence.
     *   - `rigTemplateMappings`  — `trial` → `post-and-collect-default`.
     *   - `tools`                — the manifest CLI surface
     *                               (`nsg lab trial-post`).
     */
    supportKit: {
      engines,
      rigTemplates,
      rigTemplateMappings,
      tools,
    },

    async start() {
      // Register the `trial` writ type with the Clerk. The
      // registration window closes at framework `phase:started`;
      // calling later throws.
      const clerk = guild().apparatus<ClerkApi>('clerk');
      clerk.registerWritType(TRIAL_WRIT_TYPE_CONFIG);
    },
  },
};

export default laboratoryPlugin;

/**
 * The Laboratory — public types.
 *
 * Two concerns live here:
 *
 *   1. The `trial` writ type configuration — its state machine, registered
 *      with the Clerk at startup. Mirrors the mandate lifecycle (`new →
 *      open → completed | failed | cancelled`, with `stuck` as a
 *      non-terminal "needs attention" state off `open`). Trials are leaves
 *      in v1 — the `experiment` parent type is reserved for v2 (see click
 *      c-momaacry).
 *
 *   2. The `ext.laboratory.config` schema — the structured trial
 *      configuration carried on every trial writ. Mirrors the YAML
 *      manifest shape exactly so the CLI's translation layer is a thin
 *      validator + post step.
 *
 * The legacy `LaboratoryConfig` (data-mirroring stub) is removed — that
 * plugin's no-op phase is over.
 *
 * See: experiments/infrastructure/setup-and-artifacts.md (the standalone-bash
 * spec the apparatus supersedes; its run.yaml shape is the template here).
 */

import type { WritTypeConfig } from '@shardworks/clerk-apparatus';

// ── Writ-type configuration ──────────────────────────────────────────

/** The writ-type name registered with the Clerk. */
export const TRIAL_TYPE_NAME = 'trial';

/**
 * The `trial` writ type. State machine mirrors mandate's
 * `new → open → completed/failed/cancelled` with `stuck` as a
 * non-terminal off `open`. Children-cascade behavior is included so
 * trials can be nested under a future `experiment` parent without a
 * config-level migration; in v1 trials are leaves and the cascade
 * triggers are inert.
 */
export const TRIAL_WRIT_TYPE_CONFIG: WritTypeConfig = {
  name: TRIAL_TYPE_NAME,
  states: [
    {
      name: 'new',
      classification: 'initial',
      allowedTransitions: ['open', 'cancelled'],
    },
    {
      name: 'open',
      classification: 'active',
      allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'],
    },
    {
      name: 'stuck',
      classification: 'active',
      attrs: ['stuck'],
      allowedTransitions: ['open', 'failed', 'cancelled'],
    },
    {
      name: 'completed',
      classification: 'terminal',
      attrs: ['success'],
      allowedTransitions: [],
    },
    {
      name: 'failed',
      classification: 'terminal',
      attrs: ['failure'],
      allowedTransitions: [],
    },
    {
      name: 'cancelled',
      classification: 'terminal',
      attrs: ['cancelled'],
      allowedTransitions: [],
    },
  ],
  childrenBehavior: {
    allSuccess: { transition: 'completed', copyResolution: true },
    anyFailure: { transition: 'failed', copyResolution: true },
    parentTerminal: {
      transition: 'cancelled',
      resolution: 'Automatically cancelled due to parent termination',
    },
  },
};

// ── ext.laboratory.config schema ─────────────────────────────────────
//
// The structured trial configuration. Mirrors the YAML manifest shape
// (see docs/laboratory/manifest-format.md once authored). Every field
// here will be validated by the manifest CLI before the trial writ is
// posted.

/**
 * Slug carried on every trial — used in disposable-surface naming
 * (codex repo, guild dir). Authored by the manifest. Length-limited at
 * the CLI boundary (see manifest-cli child); engines treat it as
 * already-validated input.
 *
 * Format target: lowercase kebab-case, alphanumeric + hyphen only,
 * 1–40 chars. Disposable-resource names of the shape
 * `trial-<slug>-<trialId-prefix>` slot below 63-char DNS / GH-repo
 * limits with margin.
 */
export type TrialSlug = string;

/**
 * One fixture declaration in a trial. Fixtures handle setup and
 * teardown of disposable surfaces (codex repos, test guilds, etc.)
 * and form a dependency DAG.
 *
 * Setup and teardown are paired engines. By convention the teardown
 * engine id is the setup id with `-setup` swapped for `-teardown`
 * (e.g. `lab.codex-setup` ↔ `lab.codex-teardown`). The `teardownEngineId`
 * field overrides this default when the convention doesn't fit.
 *
 * MVP0 ships trial-scope only — every fixture is fresh per trial,
 * torn down at trial end. The `scope` and `mutability` hooks are
 * reserved for v2 (see click c-mom19282).
 */
export interface TrialFixtureDecl {
  /** Fixture id within this trial. Referenced by `dependsOn`. */
  id: string;
  /** Setup engine design id (e.g. `'lab.codex-setup'`). */
  engineId: string;
  /** Override teardown engine id. Defaults to convention (`-setup` → `-teardown`). */
  teardownEngineId?: string;
  /** Givens passed to BOTH the setup and teardown engines. */
  givens: Record<string, unknown>;
  /** Other fixture ids that must be set up before this one. */
  dependsOn?: string[];
  /** Reserved for v2 — only `'trial'` valid in v1. */
  scope?: 'trial';
  /** Reserved for v2 — informational in v1. */
  mutability?: 'mutable' | 'read-only' | 'snapshotted';
}

/**
 * The scenario — what work runs inside the trial after fixtures are
 * up. In v1, scenarios are themselves engine designs (commission-post-
 * xguild + wait-for-writ-terminal-xguild are the canonical pair).
 * Future scenarios may compose multiple engine invocations.
 */
export interface TrialScenarioDecl {
  /** Engine design id to run as the scenario. */
  engineId: string;
  /** Givens passed to the scenario engine. */
  givens: Record<string, unknown>;
}

/** A probe — extracts data from one or more fixtures. */
export interface TrialProbeDecl {
  /** Probe id within this trial. */
  id: string;
  /** Engine design id (e.g. `'lab.probe-stacks-dump'`). */
  engineId: string;
  /** Givens passed to the probe engine. */
  givens: Record<string, unknown>;
}

/**
 * The archive declaration — where probe outputs land at trial end.
 * The engine and storage layout are being designed under click
 * c-momaa5o9; this shape is provisional.
 */
export interface TrialArchiveDecl {
  /** Engine design id (e.g. `'lab.archive'`). */
  engineId: string;
  /** Givens passed to the archive engine. */
  givens: Record<string, unknown>;
}

/**
 * The structured payload carried on every trial writ at
 * `ext.laboratory.config`. The manifest YAML on disk has the same
 * shape plus a top-level `description` field that lands on the writ
 * body instead of in `ext`.
 */
export interface LaboratoryTrialConfig {
  /** Trial slug (used in disposable-surface naming). */
  slug: TrialSlug;
  /** Fixtures to set up (DAG; topo-sort happens at template time). */
  fixtures: TrialFixtureDecl[];
  /** The workload that runs after setup. */
  scenario: TrialScenarioDecl;
  /** Probes to extract data. Run after the scenario reaches its end-condition. */
  probes: TrialProbeDecl[];
  /** Archive — where probe outputs go. */
  archive: TrialArchiveDecl;
}

// ── GuildConfig augmentation ─────────────────────────────────────────
//
// The Laboratory contributes no top-level guild.json config in v1.
// Trial-specific configuration lives on individual writs at
// `ext.laboratory.config`, not in guild config. Reserved for future
// global lab settings (e.g. default codex org, archive root path).

export interface LaboratoryConfig {
  /**
   * Reserved for v2. No fields read in v1 — present so guild.json
   * fragments that include an empty `laboratory: {}` block still
   * typecheck.
   */
  reserved?: never;
}

declare module '@shardworks/nexus-core' {
  interface GuildConfig {
    laboratory?: LaboratoryConfig;
  }
}

/**
 * Engine bag — every engine the Laboratory contributes via supportKit.
 *
 * Keys are the engine design ids the Spider's template references.
 * The Fabricator scans this object at startup and registers each
 * design under the laboratory plugin id.
 *
 * The five phase orchestrators (`lab.{setup,scenario,probes,archive,
 * teardown}-phase`) form the rig template's static backbone; they
 * read `writ.ext.laboratory.config` at run time and emit per-phase
 * grafts. The other engines (codex/guild fixtures, scenario,
 * probes, archive) are the work engines those grafts reference.
 *
 * Stubs land their real implementations under their respective
 * implementation children.
 */

import type { EngineDesign } from '@shardworks/fabricator-apparatus';
import { phaseEngines } from './phases.ts';
import { codexSetupEngine, codexTeardownEngine } from './codex-fixture.ts';
import { guildSetupEngine, guildTeardownEngine } from './guild-fixture.ts';
import {
  commissionPostXguildEngine,
  waitForWritTerminalXguildEngine,
} from './scenario-xguild.ts';
import {
  archiveStub,
  probeGitRangeStub,
  probeStacksDumpStub,
} from './stubs.ts';

export const engines: Record<string, EngineDesign> = {
  // Phase orchestrators (template backbone)
  ...phaseEngines,

  // Work engines (graft targets)
  'lab.codex-setup': codexSetupEngine,
  'lab.codex-teardown': codexTeardownEngine,
  'lab.guild-setup': guildSetupEngine,
  'lab.guild-teardown': guildTeardownEngine,
  'lab.commission-post-xguild': commissionPostXguildEngine,
  'lab.wait-for-writ-terminal-xguild': waitForWritTerminalXguildEngine,
  'lab.probe-stacks-dump': probeStacksDumpStub,
  'lab.probe-git-range': probeGitRangeStub,
  'lab.archive': archiveStub,
};

/**
 * Skeleton (stub) engine implementations — for engines that have not yet
 * been replaced by real code. Stubs log, yield a placeholder payload,
 * and return `{ status: 'completed' }` so the rig template's wiring
 * stays exercised end-to-end while implementation lands incrementally.
 *
 * Remaining stubs and the click that lands their real implementation:
 *
 *   - lab.probe-stacks-dump
 *     lab.probe-git-range                            — c-momaa3w7
 *   - lab.archive                                    — c-momaa5o9
 *
 * When swapping a stub for its real implementation, move it to its own
 * file under `engines/`; `stubs.ts` shrinks toward empty.
 *
 * Already replaced:
 *   - lab.codex-setup / lab.codex-teardown          (c-moma9y1k)
 *     → see `engines/codex-fixture.ts`.
 *   - lab.guild-setup / lab.guild-teardown          (c-momaa03d)
 *     → see `engines/guild-fixture.ts`.
 *   - lab.commission-post-xguild
 *     lab.wait-for-writ-terminal-xguild             (c-momaa1vt)
 *     → see `engines/scenario-xguild.ts`.
 */

import type { EngineDesign, EngineRunResult } from '@shardworks/fabricator-apparatus';

/**
 * Build a stub engine: yields a placeholder, returns completed. No
 * console output — a daemon running concurrent rigs would otherwise
 * see stub chatter dominate its logs.
 */
function stubEngine(designId: string, summary: string): EngineDesign {
  return {
    id: designId,
    async run(givens): Promise<EngineRunResult> {
      return {
        status: 'completed',
        yields: {
          stub: true,
          designId,
          summary,
          // Echo a minimal subset of givens so downstream stubs can
          // resolve `${yields.<id>.<key>}` templates without crashing.
          givenKeys: Object.keys(givens),
        },
      };
    },
  };
}

// ── Fixture engines ──────────────────────────────────────────────────

// lab.codex-setup / lab.codex-teardown moved to codex-fixture.ts.
// lab.guild-setup / lab.guild-teardown moved to guild-fixture.ts.

// ── Scenario engines ─────────────────────────────────────────────────

// lab.commission-post-xguild / lab.wait-for-writ-terminal-xguild moved
// to scenario-xguild.ts.

// ── Probe engines ────────────────────────────────────────────────────

export const probeStacksDumpStub = stubEngine(
  'lab.probe-stacks-dump',
  'export every book in test guild as JSON-per-table with carve-out for >50KB rows',
);

export const probeGitRangeStub = stubEngine(
  'lab.probe-git-range',
  'capture per-commit diffs + commits-manifest.yaml between base and head SHAs',
);

// ── Archive engine ───────────────────────────────────────────────────

export const archiveStub = stubEngine(
  'lab.archive',
  'archive probe outputs to the configured target (open: lab books vs sanctum vs hybrid; c-momaa5o9)',
);

