1	/**
2	 * lab.codex-setup / lab.codex-teardown — fixture engines for a per-trial
3	 * "upstream" codex.
4	 *
5	 * MOTIVATION
6	 * ──────────
7	 * A trial wants a codex its test guild can read from and seal into —
8	 * pinned at a known base SHA, isolated per trial, disposable at the end.
9	 *
10	 * v1 uses a LOCAL bare repo per trial (no GitHub round-trip, no token
11	 * dependencies, no org permissions, simpler teardown). The codex is
12	 * registered with the lab-host guild's Scriptorium via its standard
13	 * `add(name, remoteUrl)` API; `remoteUrl` here is just the absolute
14	 * filesystem path to the bare repo, which `git clone --bare` accepts
15	 * natively.
16	 *
17	 * SETUP FLOW
18	 * ──────────
19	 * 1. Validate givens.
20	 * 2. Resolve the bare-repo path:
21	 *      <labHostGuild>/.nexus/laboratory/codexes/<codexName>.git
22	 *    Refuse if it already exists (idempotency / safety).
23	 * 3. Clone `upstreamRepo` to a temporary working dir.
24	 * 4. `git checkout <baseSha>` in the temp clone.
25	 * 5. `git init --bare <bare-path>`.
26	 * 6. From the temp clone, `git push <bare-path> HEAD:main`. The bare's
27	 *    `main` now points at `baseSha`.
28	 * 7. Remove the temp dir.
29	 * 8. Register the bare with the lab-host's Scriptorium via
30	 *    `scriptorium.add(codexName, bare-path)`. This clones the bare to
31	 *    `<labHostGuild>/.nexus/codexes/<codexName>.git` for guild use.
32	 * 9. Yield codexName, remoteUrl, baseSha, headSha (= baseSha at setup),
33	 *    bareLocalPath.
34	 *
35	 * Failure handling: any error mid-setup triggers best-effort rollback
36	 * (unregister codex, remove bare, remove temp) and re-throws. Setup is
37	 * all-or-nothing — either every side effect lands or every side effect
38	 * is undone.
39	 *
40	 * TEARDOWN FLOW
41	 * ─────────────
42	 * 1. Validate givens.
43	 * 2. Archive-safety check: refuse to teardown if `context.upstream.archive`
44	 *    is missing — structurally indicates the rig didn't reach the archive
45	 *    phase. Once the archive engine is real (click c-momaa5o9), this
46	 *    check tightens (e.g. checks `archived === true`).
47	 * 3. `scriptorium.remove(codexName)` — abandons drafts, removes the
48	 *    bare-clone at `.nexus/codexes/<name>.git`, removes the registry
49	 *    entry from `guild.json`. Tolerant of "codex not registered" — the
50	 *    setup engine may have failed before registering.
51	 * 4. `rm -rf <bareLocalPath>`. Tolerant of "path doesn't exist".
52	 * 5. Yield `{ removed: true, codexName, bareLocalPath }`.
53	 *
54	 * GIVENS (setup AND teardown — fixture givens are shared)
55	 * ───────────────────────────────────────────────────────
56	 *   upstreamRepo : string  — any git clone source (owner/name, URL, or
57	 *                            absolute path). Passed unchanged to git.
58	 *   baseSha      : string  — 40-char SHA to seed the codex at.
59	 *   codexName    : string  — OPTIONAL. Codex name within the lab-host
60	 *                            guild; also used as the bare-repo dir name.
61	 *                            Defaults to `<slug>-<writId-tail>` derived
62	 *                            from the framework-injected `_trial` context
63	 *                            (which the phase orchestrators populate from
64	 *                            the trial writ). Override when the default
65	 *                            isn't what you want.
66	 *
67	 * YIELDS (setup)
68	 * ──────────────
69	 *   {
70	 *     codexName: string,
71	 *     remoteUrl: string,        // absolute path to the bare; same as bareLocalPath
72	 *     bareLocalPath: string,    // explicit alias for clarity downstream
73	 *     baseSha: string,          // echoed
74	 *     headSha: string,          // = baseSha at setup; updated by trial work
75	 *   }
76	 *
77	 * YIELDS (teardown)
78	 * ─────────────────
79	 *   { removed: true, codexName: string, bareLocalPath: string }
80	 */
81	
82	import { execFile as execFileCb } from 'node:child_process';
83	import { promisify } from 'node:util';
84	import { existsSync } from 'node:fs';
85	import { mkdtemp, mkdir, rm } from 'node:fs/promises';
86	import path from 'node:path';
87	import os from 'node:os';
88	import { guild } from '@shardworks/nexus-core';
89	import type {
90	  EngineDesign,
91	  EngineRunContext,
92	  EngineRunResult,
93	} from '@shardworks/fabricator-apparatus';
94	import type { ScriptoriumApi } from '@shardworks/codexes-apparatus';
95	import type { InjectedTrialContext } from './phases.ts';
96	
97	const execFile = promisify(execFileCb);
98	
99	// ── Givens validation ────────────────────────────────────────────────
100	
101	interface CodexFixtureGivens {
102	  upstreamRepo: string;
103	  baseSha: string;
104	  codexName: string;
105	}
106	
107	const SHA_PATTERN = /^[0-9a-f]{40}$/i;
108	
109	/**
110	 * Codex name rules — used both as the Scriptorium codex name AND as the
111	 * bare repo's directory name. Conservative: kebab-case, 1–60 chars.
112	 * Codex names are scoped to the lab-host guild and only need to be
113	 * unique among concurrent trials.
114	 */
115	const CODEX_NAME_PATTERN = /^[a-z][a-z0-9-]{0,59}$/;
116	
117	/**
118	 * Derive the suffix used in the auto-generated codex name. The trial
119	 * writ id is shaped `w-<timestamp>-<hash>` (e.g.
120	 * `w-momen904-e8cd1359f754`); we take the trailing hash and slice 8
121	 * chars. Falls back to the first 8 chars of the id when no hyphens.
122	 */
123	export function writIdTail(writId: string): string {
124	  const trailing = writId.split('-').pop() ?? writId;
125	  return trailing.slice(0, 8);
126	}
127	
128	/**
129	 * Compute the default codex name from the framework-injected `_trial`
130	 * context: `<slug>-<writIdTail>`. Returns null when `_trial` is missing
131	 * or malformed (caller throws with a clear message rather than silently
132	 * picking a meaningless default).
133	 */
134	function defaultCodexName(givens: Record<string, unknown>): string | null {
135	  const trial = givens._trial as InjectedTrialContext | undefined;
136	  if (!trial || typeof trial.slug !== 'string' || typeof trial.writId !== 'string') {
137	    return null;
138	  }
139	  return `${trial.slug}-${writIdTail(trial.writId)}`;
140	}
141	
142	function validateGivens(
143	  givens: Record<string, unknown>,
144	  designId: string,
145	): CodexFixtureGivens {
146	  const upstreamRepo = givens.upstreamRepo;
147	  const baseSha = givens.baseSha;
148	  let codexName = givens.codexName;
149	
150	  if (typeof upstreamRepo !== 'string' || upstreamRepo.length === 0) {
151	    throw new Error(
152	      `[${designId}] givens.upstreamRepo is required and must be a non-empty string ` +
153	        `(any git clone source: owner/name, URL, or absolute path).`,
154	    );
155	  }
156	  if (typeof baseSha !== 'string' || !SHA_PATTERN.test(baseSha)) {
157	    throw new Error(
158	      `[${designId}] givens.baseSha must be a 40-char hex SHA; got "${String(baseSha)}".`,
159	    );
160	  }
161	
162	  // Default codexName from injected trial context when not supplied.
163	  if (codexName === undefined || codexName === null) {
164	    const fallback = defaultCodexName(givens);
165	    if (fallback === null) {
166	      throw new Error(
167	        `[${designId}] givens.codexName is missing and no _trial context was injected. ` +
168	          `Either author codexName explicitly, or ensure the engine runs under the ` +
169	          `Laboratory phase orchestrators (which inject _trial automatically).`,
170	      );
171	    }
172	    codexName = fallback;
173	  }
174	
175	  if (typeof codexName !== 'string' || !CODEX_NAME_PATTERN.test(codexName)) {
176	    throw new Error(
177	      `[${designId}] codexName must be kebab-case (start with a letter; ` +
178	        `alphanumeric and hyphens; ≤60 chars); got "${String(codexName)}".`,
179	    );
180	  }
181	
182	  return { upstreamRepo, baseSha, codexName };
183	}
184	
185	// ── Path helpers ─────────────────────────────────────────────────────
186	
187	/**
188	 * Resolve the bare-repo path for a trial codex inside the lab-host
189	 * guild's filesystem. Namespaced under `.nexus/laboratory/codexes/` —
190	 * adjacent to the codexes plugin's own `.nexus/codexes/` (which holds
191	 * the auto-clone the Scriptorium creates from this bare) but distinct
192	 * from it.
193	 */
194	export function bareRepoPath(labHostGuildHome: string, codexName: string): string {
195	  return path.join(labHostGuildHome, '.nexus', 'laboratory', 'codexes', `${codexName}.git`);
196	}
197	
198	// ── Git ──────────────────────────────────────────────────────────────
199	
200	/**
201	 * Lightweight git wrapper — execFile-based (no shell), trims output.
202	 * Mirrors the codexes plugin's internal helper but we keep our own copy
203	 * to avoid coupling to a non-exported symbol.
204	 */
