1	/**
2	 * Trial manifest — YAML format, zod schema, parser, and validator.
3	 *
4	 * The manifest is the authoring surface for trials. Its shape mirrors
5	 * `LaboratoryTrialConfig` exactly, with two additions:
6	 *
7	 *   - `description` — optional prose that becomes the trial writ's
8	 *     body (free-form, no structural meaning).
9	 *   - `title` — optional short title that becomes the trial writ's
10	 *     title (defaults to `Trial: <slug>`).
11	 *
12	 * The manifest also accepts optional `parentId` and `codex` fields
13	 * for clerk's writ-post API; both are passed through to clerk.post
14	 * unchanged.
15	 *
16	 * Manifest YAML example:
17	 *
18	 *     slug: orientation-suppression-strong-prompt
19	 *     title: P3 orientation suppression — strong prompt variant
20	 *     description: |
21	 *       Tests whether an imperative anti-orientation directive in the
22	 *       implementer handoff produces productive work in <5 turns.
23	 *
24	 *     fixtures:
25	 *       - id: codex
26	 *         engineId: lab.codex-setup
27	 *         givens:
28	 *           # Any git clone source: owner/name (gh-default), full URL, or
29	 *           # an absolute local path. Trial codex is a local bare repo —
30	 *           # no GitHub required.
31	 *           upstreamRepo: /workspace/nexus-mk2
32	 *           baseSha: <40-char>
33	 *           # codexName is optional — defaults to <slug>-<writId-tail>,
34	 *           # which is unique-by-construction and traces back to the trial.
35	 *           # Override only when you want a specific name.
36	 *
37	 *       - id: test-guild
38	 *         engineId: lab.guild-setup
39	 *         dependsOn: [codex]
40	 *         givens:
41	 *           plugins: [...]
42	 *           config: { ... }
43	 *           files: [...]
44	 *
45	 *     scenario:
46	 *       engineId: lab.commission-post-xguild
47	 *       givens:
48	 *         briefPath: files/brief.md
49	 *
50	 *     probes:
51	 *       - id: stacks
52	 *         engineId: lab.probe-stacks-dump
53	 *         givens:
54	 *           outputPath: stacks-export/
55	 *
56	 *     archive:
57	 *       engineId: lab.archive
58	 *       givens: {}
59	 *
60	 * The parser:
61	 *   1. Reads the YAML file.
62	 *   2. Parses it into a JS object.
63	 *   3. Validates against `manifestSchema`.
64	 *   4. Cross-validates fixture DAG (cycles, unknown deps, dup ids).
65	 *   5. Splits into a writ-post shape and the trial config that goes
66	 *      under `ext.laboratory.config`.
67	 */
68	
69	import { readFile } from 'node:fs/promises';
70	import { parse as parseYaml } from 'yaml';
71	import { z } from 'zod';
72	import type {
73	  LaboratoryTrialConfig,
74	  TrialFixtureDecl,
75	  TrialScenarioDecl,
76	  TrialProbeDecl,
77	  TrialArchiveDecl,
78	} from './types.ts';
79	import { topoSortFixtures } from './engines/phases.ts';
80	
81	// ── Slug ──────────────────────────────────────────────────────────
82	
83	/**
84	 * Trial slug rules (used in disposable-surface naming):
85	 *   - lowercase alphanumeric and hyphens only
86	 *   - must start with a letter
87	 *   - 1–40 characters
88	 *
89	 * `trial-<slug>-<trialId-prefix>` (the codex/repo naming format)
90	 * with a 40-char slug and an 8-char id-prefix sums to 55 chars,
91	 * comfortably under the 63-char DNS / GH-repo limit.
92	 */
93	export const SLUG_PATTERN = /^[a-z][a-z0-9-]{0,39}$/;
94	export const SLUG_MAX_LENGTH = 40;
95	
96	const slugSchema = z.string().regex(
97	  SLUG_PATTERN,
98	  'must be lowercase kebab-case (start with a letter; alphanumeric and hyphens; ≤40 chars)',
99	);
100	
101	// ── Sub-schemas ───────────────────────────────────────────────────
102	
103	const givensSchema = z.record(z.string(), z.unknown()).default({});
104	
105	const fixtureSchema = z.object({
106	  id: z
107	    .string()
108	    .min(1, 'must be non-empty')
109	    .regex(/^[a-z][a-z0-9-]{0,39}$/, 'fixture id must be kebab-case (≤40 chars)'),
110	  engineId: z.string().min(1, 'engineId is required'),
111	  teardownEngineId: z.string().min(1).optional(),
112	  givens: givensSchema,
113	  dependsOn: z.array(z.string()).optional(),
114	  scope: z.literal('trial').optional(),
115	  mutability: z.enum(['mutable', 'read-only', 'snapshotted']).optional(),
116	}) satisfies z.ZodType<TrialFixtureDecl>;
117	
118	const scenarioSchema = z.object({
119	  engineId: z.string().min(1, 'engineId is required'),
120	  givens: givensSchema,
121	}) satisfies z.ZodType<TrialScenarioDecl>;
122	
123	const probeSchema = z.object({
124	  id: z
125	    .string()
126	    .min(1)
127	    .regex(/^[a-z][a-z0-9-]{0,39}$/, 'probe id must be kebab-case (≤40 chars)'),
128	  engineId: z.string().min(1, 'engineId is required'),
129	  givens: givensSchema,
130	}) satisfies z.ZodType<TrialProbeDecl>;
131	
132	const archiveSchema = z.object({
133	  engineId: z.string().min(1, 'engineId is required'),
134	  givens: givensSchema,
135	}) satisfies z.ZodType<TrialArchiveDecl>;
136	
137	// ── Top-level manifest ────────────────────────────────────────────
138	
139	export const manifestSchema = z.object({
140	  slug: slugSchema,
141	  title: z.string().min(1).optional(),
142	  description: z.string().optional(),
143	  parentId: z.string().min(1).optional(),
144	  codex: z.string().min(1).optional(),
145	  fixtures: z.array(fixtureSchema).default([]),
146	  scenario: scenarioSchema,
147	  probes: z.array(probeSchema).default([]),
148	  archive: archiveSchema,
149	});
150	
151	export type TrialManifest = z.output<typeof manifestSchema>;
152	
153	// ── Parsing & validation ──────────────────────────────────────────
154	
155	/**
156	 * Errors thrown by the manifest parser. The CLI catches these and
157	 * presents them with the manifest file path for actionable feedback.
158	 */
159	export class ManifestError extends Error {
160	  constructor(message: string) {
161	    super(message);
162	    this.name = 'ManifestError';
163	  }
164	}
165	
166	/**
167	 * Parse and fully validate a manifest from a YAML string.
168	 *
169	 * Validation order:
170	 *   1. YAML syntactic parse.
171	 *   2. Schema validation (zod).
172	 *   3. Cross-field validation:
173	 *      - fixture id uniqueness (caught by topoSort)
174	 *      - fixture dependsOn references valid (caught by topoSort)
175	 *      - fixture dep DAG acyclic (caught by topoSort)
176	 *      - probe id uniqueness within probes
177	 */
178	export function parseManifest(yamlText: string): TrialManifest {
179	  let raw: unknown;
180	  try {
181	    raw = parseYaml(yamlText);
182	  } catch (err) {
183	    throw new ManifestError(`YAML parse failed: ${(err as Error).message}`);
184	  }
185	
186	  if (raw === null || raw === undefined) {
187	    throw new ManifestError('manifest is empty');
188	  }
189	  if (typeof raw !== 'object' || Array.isArray(raw)) {
190	    throw new ManifestError('manifest must be a YAML map at the top level');
191	  }
192	
193	  const parsed = manifestSchema.safeParse(raw);
194	  if (!parsed.success) {
195	    const issues = parsed.error.issues
196	      .map((issue) => `  - ${issue.path.join('.')}: ${issue.message}`)
197	      .join('\n');
198	    throw new ManifestError(`manifest schema validation failed:\n${issues}`);
199	  }
200	
201	  // Cross-field: fixture DAG
202	  try {
203	    topoSortFixtures(parsed.data.fixtures);
204	  } catch (err) {
205	    throw new ManifestError(`fixture DAG invalid: ${(err as Error).message}`);
206	  }
207	
208	  // Cross-field: probe id uniqueness
209	  const probeIds = new Set<string>();
210	  for (const probe of parsed.data.probes) {
211	    if (probeIds.has(probe.id)) {
212	      throw new ManifestError(`duplicate probe id: "${probe.id}"`);
213	    }
214	    probeIds.add(probe.id);
215	  }
216	
217	  return parsed.data;
218	}
219	
220	/**
221	 * Read a manifest file, parse it, and validate. Convenience wrapper
222	 * for the CLI's most common entry path. Wraps file-read errors with
223	 * the manifest path.
224	 */
225	export async function readManifestFile(filePath: string): Promise<TrialManifest> {
226	  let text: string;
227	  try {
228	    text = await readFile(filePath, 'utf8');
229	  } catch (err) {
230	    throw new ManifestError(
231	      `failed to read manifest at ${filePath}: ${(err as Error).message}`,
232	    );
233	  }
234	  try {
235	    return parseManifest(text);
236	  } catch (err) {
237	    if (err instanceof ManifestError) {
238	      // Re-throw with the path prefix so error messages are
239	      // immediately actionable from the CLI.
240	      throw new ManifestError(`${filePath}: ${err.message}`);
241	    }
242	    throw err;
243	  }
244	}
245	
246	/**
247	 * Split a parsed manifest into the shape clerk.post expects plus the
248	 * trial config that lands under `ext.laboratory.config`. The split
249	 * is a pure-data transform; no side effects, no clerk lookups.
250	 */
251	export function manifestToWritShape(manifest: TrialManifest): {
252	  title: string;
253	  body: string;
254	  parentId?: string;
255	  codex?: string;
256	  trialConfig: LaboratoryTrialConfig;
257	} {
258	  const trialConfig: LaboratoryTrialConfig = {
259	    slug: manifest.slug,
260	    fixtures: manifest.fixtures,
261	    scenario: manifest.scenario,
262	    probes: manifest.probes,
263	    archive: manifest.archive,
264	  };
265	  return {
266	    title: manifest.title ?? `Trial: ${manifest.slug}`,
267	    body: manifest.description ?? '',
268	    parentId: manifest.parentId,
269	    codex: manifest.codex,
270	    trialConfig,
271	  };
272	}
