   * Absolute path to a directory the probe is allowed to write into.
   * Created by the caller before invocation. Probes should write under
   * a probe-specific subdirectory (or single file) so multiple probes
   * can share the same `targetDir` without colliding.
   */
  targetDir: string;
}

/** Result of a probe's extract handler. */
export interface ProbeExtractResult {
  /**
   * Files the probe wrote, with paths relative to `targetDir` and
   * byte counts. Used by the extract tool's summary output.
   */
  files: Array<{ path: string; bytes: number }>;
}

/** A probe extract handler. */
export type ProbeExtractor = (args: ProbeExtractArgs) => Promise<ProbeExtractResult>;

/**
 * A probe's full contribution to the laboratory plugin — the engine
 * design (registered via supportKit.engines), an optional book schema
 * (registered via supportKit.books), and the extract handler
 * (registered with the probe registry below).
 */
export interface ProbeContribution {
  /** Engine design id (e.g. `'lab.probe-stacks-dump'`). */
  engineId: string;
  /** The engine design — folded into supportKit.engines. */
  engine: EngineDesign;
  /**
   * Books this probe owns, keyed by book name. Folded into
   * supportKit.books at the laboratory plugin's `'laboratory'`
   * owner id. May be omitted for summary-only probes.
   */
  books?: Record<string, BookSchema>;
  /** The extract handler — registered with the registry. */
  extractor: ProbeExtractor;
}

