const probeRegistry = new Map<string, ProbeExtractor>();

/**
 * Register a probe with the laboratory's probe registry. Called from
 * `index.ts` during plugin init for each built-in probe; idempotent
 * (re-registering the same id with the same extractor is a no-op,
 * with a different extractor it's a fail-loud collision).
 */
export function registerProbe(probe: ProbeContribution): void {
  const existing = probeRegistry.get(probe.engineId);
  if (existing && existing !== probe.extractor) {
    throw new Error(
      `[laboratory] probe "${probe.engineId}" is already registered with a different extractor; ` +
        `re-registering with a new handler is not supported (would silently shadow probe code).`,
    );
  }
  probeRegistry.set(probe.engineId, probe.extractor);
}

