 * Look up a probe extractor by engine id. Returns undefined when the
 * id is not registered — the trial-extract tool surfaces this as
 * "no extractor for engine id <X>; install the probe's plugin or
 * skip the probe with --skip-engine".
 */
export function getProbeExtractor(engineId: string): ProbeExtractor | undefined {
  return probeRegistry.get(engineId);
}

/** Snapshot of registered probe ids. Useful for diagnostics. */
export function listRegisteredProbes(): string[] {
  return [...probeRegistry.keys()].sort();
}

/** Test-only: drop every registration. Production code never calls this. */
export function clearProbeRegistry(): void {
  probeRegistry.clear();
}

