/**
 * Extractor for `lab.probe-trial-context`. Materializes the probe's
 * captured trial-context summary as a single YAML file at
 * `<targetDir>/trial-context.yaml`.
 *
 * The summary is a row in `lab-trial-archives.probes[].summary`,
 * keyed by the engineId. Reading from the archive book — not a
 * dedicated trial-context book — keeps the probe summary-only.
 */

import { writeFile, mkdir } from 'node:fs/promises';
import path from 'node:path';
import { stringify as yamlStringify } from 'yaml';
import { guild } from '@shardworks/nexus-core';
import type { ReadOnlyBook, StacksApi } from '@shardworks/stacks-apparatus';
import type { ProbeExtractor } from '../registry.ts';
import { LAB_TRIAL_ARCHIVES_BOOK, type LabTrialArchive } from '../../archive/book.ts';

const DESIGN_ID = 'lab.probe-trial-context';
const RELATIVE_PATH = 'trial-context.yaml';

export const extractTrialContext: ProbeExtractor = async ({ trialId, targetDir }) => {
  const stacks = guild().apparatus<StacksApi>('stacks');
  const archives: ReadOnlyBook<LabTrialArchive> = stacks.readBook<LabTrialArchive>(
    'laboratory',
    LAB_TRIAL_ARCHIVES_BOOK,
  );
  const rows = await archives.find({ where: [['trialId', '=', trialId]] });
  if (rows.length === 0) {
    throw new Error(
      `[lab.probe-trial-context extractor] no archive row for trialId=${trialId}; ` +
        `the trial may have failed before reaching the archive engine.`,
    );
  }
  const probe = rows[0]!.probes.find((p) => p.engineId === DESIGN_ID);
  if (!probe) {
    // Probe wasn't part of this trial — silent no-op.
    return { files: [] };
  }

  await mkdir(targetDir, { recursive: true });
  const fullPath = path.join(targetDir, RELATIVE_PATH);
  const yamlText = yamlStringify(probe.summary);
  await writeFile(fullPath, yamlText, 'utf8');
  return { files: [{ path: RELATIVE_PATH, bytes: Buffer.byteLength(yamlText, 'utf8') }] };
};

