function makeTrialConfig(): LaboratoryTrialConfig {
  return {
    slug: 'integ-trial',
    fixtures: [
      { id: 'codex', engineId: 'lab.codex-setup', givens: {} },
      {
        id: 'test-guild',
        engineId: 'lab.guild-setup',
        dependsOn: ['codex'],
        givens: {},
