  engineId: lab.archive
`),
      (err: Error) => {
        assert.match(err.message, /unstable pin/);
        assert.match(err.message, /not reproducible/);
        assert.match(err.message, /fixtures\.0\.givens\.plugins\.0\.version/);
        return true;
      },
    );
  });

