      plugins:
        - { name: x, version: 'link:../somewhere' }
scenario:
  engineId: lab.scenario
archive:
  engineId: lab.archive
`),
      /unstable pin.*pnpm-only/,
    );
  });

  it('rejects caret ranges', () => {
    assert.throws(
      () =>
        parseManifest(`
slug: ok
