    assert.throws(
      () =>
        parseManifest(`
slug: ok
fixtures:
  - id: g
    engineId: lab.guild-setup
    givens:
      plugins:
        - { name: x, version: 'latest' }
scenario:
  engineId: lab.scenario
archive:
  engineId: lab.archive
`),
      /dist-tag/,
    );
  });

