/**
 * lab.archive — write the archive index row for a trial.
 *
 * Reads probe summaries from `context.upstream` and writes one atomic
 * row to `lab-trial-archives` describing which probes ran in this
 * trial and what each yielded as a summary.
 *
 * Per-engine atomicity: the rig grafts probes ahead of the archive
 * engine; each probe writes its bulk data atomically inside its own
 * SQLite transaction. The archive engine writes its index row
 * atomically once. Trials whose rigs failed before reaching archive
 * simply have no matching row; orphan probe rows are tolerated and
 * filtered out by every analytical query (joins start from
 * `lab-trial-archives` outward).
 *
 * Probe discovery: walks `context.upstream` for entries keyed
 * `probe-<id>` (the engine-id naming convention from
 * engines/phases.ts → PROBE_ID). Pairing the probe id back to its
 * engineId requires reading the trial config off the writ, which
 * the engine fetches via the Clerk using the framework-injected
 * `_trial.writId` (the static rig template's `${writ}` substitution
 * applies only to pre-graft engines).
 *
 * GIVENS
 * ──────
 *   _trial : InjectedTrialContext  — framework-injected by the
 *                                    archive-phase orchestrator;
 *                                    `_trial.writId` identifies the
 *                                    trial writ to fetch.
 *
 * SUMMARY (yields)
 * ────────────────
 *   {
 *     archiveId       : string,
 *     trialId         : string,
 *     probeCount      : number,
 *     archivedAt      : string,
 *   }
 */

import { guild, generateId } from '@shardworks/nexus-core';
import type {
  EngineDesign,
  EngineRunContext,
  EngineRunResult,
} from '@shardworks/fabricator-apparatus';
import type { Book, StacksApi } from '@shardworks/stacks-apparatus';
import type { ClerkApi, WritDoc } from '@shardworks/clerk-apparatus';
import type { LaboratoryTrialConfig } from '../types.ts';
import { PROBE_ID, type InjectedTrialContext } from '../engines/phases.ts';
import {
  LAB_TRIAL_ARCHIVES_BOOK,
  type ArchivedProbeEntry,
  type LabTrialArchive,
} from './book.ts';

const DESIGN_ID = 'lab.archive';

interface ResolvedGivens {
  writ: WritDoc;
  config: LaboratoryTrialConfig;
}

/**
 * Resolve the trial writ for archive-row construction. Reads the
 * trial id from the framework-injected `_trial.writId` (every
 * grafted engine's givens carry it) and fetches the writ via the
 * Clerk so the archive sees the live `ext.laboratory.config` —
 * including any fields the trial-post tool resolved post-manifest
 * (e.g. `frameworkVersion` defaulting from the lab-host).
 *
 * The static rig template's `${writ}` substitution applies only to
 * pre-graft engines (the five phase orchestrators); grafted engines
 * inherit no implicit writ reference. Reading via clerk avoids
 * coupling the orchestrator's graft to template-variable mechanics.
 */
async function resolveWritAndConfig(
  rawGivens: Record<string, unknown>,
): Promise<ResolvedGivens> {
  const trial = rawGivens._trial as InjectedTrialContext | undefined;
